var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"크학......!","JPN":"ぐはっ……！","ENG":"Ack!","TWN":"啊……！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"형님! 놈들이 워낙 거칠게 저항해서 들어가기 힘듭니다!","JPN":"兄貴！　抵抗が激しく、中に入れそうにありません！","ENG":"Sir! They're fighting too hard for us to make a breach!","TWN":"大哥！他們抵抗太頑強了，無法繼續前進！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"이 등신들 같으니...... 구석에 몰아 넣은 들개들도 못 잡아서 빌빌대?","JPN":"使えねえな……追い込んだドブネズミ数匹も始末できねえのか？","ENG":"You good-for-nothing idiots... We've got them cornered!","TWN":"沒用的東西……對方都被逼到死角了，你們還拿他們沒辦法嗎？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"뭐 해! 걸리적거리니까 저 멍청한 놈 어서 치워!","JPN":"何やってんだ！　邪魔だからあのバカを早く片付けろ！","ENG":"Don't just stand around! Get that idiot out of the way!","TWN":"愣著幹什麼！快幹掉那個礙眼的傢伙！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"저 녀석들...... 수가 너무 많아. 어쩌지?","JPN":"こいつら……数が多すぎる。どうする？","ENG":"There's too many of them. What should we do?","TWN":"敵人數量……實在太多了。怎麼辦？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"한 놈 죽으면 두 놈 더 늘어나는군. 꽤 작정하고 온 모양인데.","JPN":"一人死んだら二人に増えてくるな。向こうも生半可な気持ちでここまで来たわけではないようだ。","ENG":"We kill one, and they bring two more. Looks like they came prepared.","TWN":"殺一個又冒出兩個，看來他們準備很充分。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그래, 대장. 이대로 여기서 버티기만 하는 건 자살 행위야.","JPN":"そうだな、隊長。このままここで踏ん張るのは自殺行為だ。","ENG":"That's right, Captain. Holding our ground like this is suicidal.","TWN":"沒錯，隊長。在這裡堅持也是死路一條。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"좋은 방법이라도 있나?","JPN":"いい方法でもあるのか？","ENG":"Got any ideas?","TWN":"你有什麼辦法嗎？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그야 없진 않지.","JPN":"なくはない。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"각개 격파라고 들어봤어?","JPN":"各個撃破って聞いたことあるか？","ENG":"Divide and conquer.","TWN":"你知道各個擊破戰術嗎？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"내가 조무래기 놈들을 여기 붙잡아 두는 동안 두 사람은 저 간부 놈을 유인하는 거야.","JPN":"俺が雑魚どもをここで足止めする間、二人はあの幹部の野郎をおびき寄せるんだ。","ENG":"While I keep the rest of the thugs pinned down, you two can lure their leader out.","TWN":"趁我對抗那些嘍囉時，你們兩個去引誘那個幹部。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"쉽게 따라오진 않을 텐데. 그러다가 우리가 각개격파 당할 수도 있어.","JPN":"簡単には釣れないはずだ。逆に俺たちが各個撃破される可能性もある。","ENG":"He won't tag along that easily. They might divide and conquer instead.","TWN":"他們不會輕易上鉤的。說不定被各個擊破的反而會是我們。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그거야 대장이 알아서 해야지. 남 열 받게 하는 게 대장 특기잖아.","JPN":"そりゃ隊長がなんとかしないと。人を怒らせるのが隊長の特技だろ。","ENG":"Well, that's up to you. You're a pro at aggravating people, you know.","TWN":"那就得靠隊長了。惹毛對方不是你的專長嗎？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"잠깐, 그런데 지훈이 너 혼자 저 많은 놈들을 붙잡아 두겠다고?","JPN":"ちょっと待って、ゴトウ一人であの大人数を足止めするって？","ENG":"Wait, how are you going to keep all those guys pinned down by yourself?","TWN":"等等，你說你要一個人困住那麼多人？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"아까는 대장이 했으니까 이번엔 내 차례지.","JPN":"さっきは隊長がやったから、今度は俺の番だ。","ENG":"That's what the Captain did earlier. It's my turn now.","TWN":"剛才隊長不也成功了嗎，這次輪到我了。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"왜, 대장은 했는데 나는 못 할 것 같아?","JPN":"なんだ、隊長はできて俺にはできないとでも思ってんのか？","ENG":"What, you think I can't do what the Captain did?","TWN":"怎麼，你覺得我做不到嗎？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그런 뜻이 아니잖아! 혼자 개죽음 당하겠다는 거야, 뭐야?!","JPN":"そういう意味じゃない！　一人で無駄死にしたいのか！？","ENG":"That's not what I mean! Are you trying to get yourself killed?!","TWN":"不是這個意思！你這不是找死嗎？！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"걱정 마라. 난 아직 못 죽어.","JPN":"心配すんな。俺はまだ死ねない。","ENG":"Don't worry. I can't die yet.","TWN":"別擔心，我死不了。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"백 살 넘어서 손주에 증손자 볼 때까지 살아남을 거다.","JPN":"100歳超えて孫と曾孫に会うまで生き残ってやる。","ENG":"I ain't dying till I live to be over a hundred with great-grandkids.","TWN":"我會活到一百歲，我要看到我的孫子、曾孫出生後再死。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......결혼해 줄 상대는 있고?","JPN":"……結婚してくれる相手はいるの？","ENG":"Who the hell's crazy enough to marry you?","TWN":"……你有對象嗎？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"팩트로 때리지 마라, 아프니까.","JPN":"直球をぶつけるな、悲しくなるだろうが。","ENG":"Stop hitting the nail on the head. It hurts.","TWN":"不用說實話沒關係，我會受傷。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"얼른 달리기나 해!","JPN":"黙って走れ！","ENG":"Just get your butts moving already!","TWN":"快跑！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"알겠다. 일이 끝나면 합류지점에서 다시 만나지.","JPN":"了解。仕事が終わったら合流地点で会おう。","ENG":"Fine. We'll rendezvous at the agreed location once this is over.","TWN":"好，事情搞定後在會合地點見吧。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"이것 참! 꼴에 영웅놀이라도 하는 거냐?","JPN":"まったく！　この状況で英雄ごっこでもするのか？","ENG":"Golly! Now you want to play hero?","TWN":"咦！就你還要逞英雄嗎？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"몰랐어? 원래 민병대는 지지리 불쌍한 놈들의 영웅이라고.","JPN":"知らなかったか？　もともと民兵隊はくそついてない哀れな連中の英雄なのさ。","ENG":"Didn't you know? The Militia are heroes for suckers.","TWN":"你不知道嗎？民兵隊本來就是可憐之人的英雄。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그나저나 영감은 아직 여기서 뭐해? 도망 안가고.","JPN":"ていうか、ジジイはここで何してるんだ？　逃げないのか？","ENG":"What are you still doing here anyway?","TWN":"老頭你幹什麼？快跑啊。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그 총은 또 뭐야? 설마 싸우려고?","JPN":"その銃はなんだ？　まさか戦うつもりか？","ENG":"And what's with the gun? You're not going to fight back, are you?","TWN":"那把槍又是什麼？難道你也想戰鬥？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"어차피 오늘 장사는 글렀어.","JPN":"どうせ今日の営業は無理だ。","ENG":"Well, I sure ain't gonna be selling them any guns today.","TWN":"反正今天沒辦法做生意了。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"저 무례한 놈들에게 이 무기상의 가게를 건드리면 어떻게 되는지 알려줄 작정이다.","JPN":"あの無礼な奴らに、この武器屋の店に手を出したらどうなるのか、思い知らせてやる。","ENG":"Instead, I'm going to teach those rude brutes what happens when they mess with my place of business.","TWN":"我要讓那些無禮之徒瞧瞧，招惹武器商的後果有多麼殘酷。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......그거 좋군.","JPN":"……いいぞ。","ENG":"Sounds good.","TWN":"……那倒不錯。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그럼 둘씩 갈라서면 되겠군. 신호하면 전력으로 달려, 이유리.","JPN":"それじゃあ2人ずつ分かれればいいな。合図したら全力で走れ、カスカベ。","ENG":"Then we'll move in groups of two. Sprint full speed ahead when I give you the signal, Yuri.","TWN":"那我們就分成兩路，等發出信號之後全力奔跑吧，李悠麗。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"혀, 형님! 수류탄입니다!","JPN":"あ、兄貴！　手榴弾です！","ENG":"S-sir! Grenade!","TWN":"大、大哥！是手榴彈！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"어쩌라는 거야? 나불댈 시간에 엎드려!","JPN":"だからどうした？　喋る暇があるなら伏せろ！","ENG":"What's the point of telling me? Just get down!","TWN":"還能怎樣？快趴下！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"뭐야, 왜 안 터지는 거지? 설마......?","JPN":"なんだ？　なんで爆発しないんだ？　まさか……？","ENG":"Huh? Why isn't it going off?","TWN":"為什麼沒爆炸？難道……？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"플라스틱 모형이다.","JPN":"プラスチックの偽物だ。","ENG":"Because it's a plastic dummy.","TWN":"那只是塑膠模型。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"카운터인 주제에 수류탄에 쫄다니 그 새가슴으로 잘도 성냥팔이 밑에 있군.","JPN":"カウンターのくせに手榴弾にビビるとは、その小さな肝っ玉でよくマッチ売りの元で働けるな。","ENG":"I didn't think a Counter would chicken out at a grenade. Does the Matchmaker know what a wuss you are?","TWN":"堂堂一個制裁者也會怕手榴彈嗎？賣火柴組織裡竟然也有你這樣的膽小鬼。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"혹시 접대 기술이 네놈 출세의 비결인가?","JPN":"もしかして、接待術がお前の出世の秘訣なのか？","ENG":"Or is your true superpower brown-nosing your way to the top?","TWN":"你是不是就靠應酬本領出人頭地的呀？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"방금 뭐라고 했어, 이 개자식이!","JPN":"今なんて言った？　クソ野郎め！","ENG":"What the hell did you just say, you bastard?!","TWN":"你說什麼，狗崽子！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"당장 거기 서지 못 해!","JPN":"そこを動くな、こら！","ENG":"Stop right there!","TWN":"給我站住！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"혼자 가시면 안 됩니다! 형님!","JPN":"一人で行ってはいけません！　兄貴！","ENG":"Sir! You shouldn't go off by yourself!","TWN":"大哥！不能一個人追！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};